class ImagesController < ApplicationController
  def create
    image = Image.new(params[:image])
    processed_image = convert_image(image, params[:format], params[:size])
    save_processed_image(processed_image)
    render json: { url: rails_blob_path(processed_image, only_path: true) }, status: :created
  end

  private

  def convert_image(image, format, size)
    command = "convert #{image.path} -resize #{size}x#{size}! #{format}: #{image.path}.#{format}"
    system(command) until File.exist?(image.path + ".#{format}")
    image.path + ".#{format}"
  end

  def save_processed_image(file_path)
    Attachment.create!(blob: ActiveStorage::Blob.create_and_upload!(io: File.open(file_path), filename: 'image', content_type: 'image/jpeg'))
  end
end